update public.notes
set content_json = $R1$
{"type":"doc","content":[{"type":"thusnessHero","content":[{"type":"paragraph","content":[{"type":"text","text":"What asks for room when resistance is met without turning it into a project?"}]},{"type":"paragraph","content":[{"type":"text","text":"— a question to sit with —"}]}]},{"type":"thusnessSectionMark","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Theme · Noticing resistance"}]}]},{"type":"paragraph","content":[{"type":"text","text":"Resistance rarely arrives with a label. Today it came as a slight narrowing behind the eyes, a reluctance to stay with one more breath, and a quiet argument that something else deserved attention."}]},{"type":"thusnessPullQuote","content":[{"type":"paragraph","content":[{"type":"text","text":"What stood out was how quickly resistance softens when it is allowed to exist without being turned into a project. Not always. Not forever. But often enough to be worth remembering."}]}]},{"type":"thusnessRuleList","content":[{"type":"paragraph","content":[{"type":"text","text":"~ How we met it"}]},{"type":"thusnessRuleListItem","content":[{"type":"paragraph","content":[{"type":"text","text":"We did not negotiate with it as an enemy. We let it be named in a plain way—tension, avoidance, the small \"no\"—and watched how it behaved when it was not chased."}]}]},{"type":"thusnessRuleListItem","content":[{"type":"paragraph","content":[{"type":"text","text":"The body already knew how to stay, once the commentary thinned."}]}]}]},{"type":"thusnessRuleList","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Afterward"}]},{"type":"thusnessRuleListItem","content":[{"type":"paragraph","content":[{"type":"text","text":"This note is a bookmark for that ordinary afternoon when the floor felt steadier after the noticing widened, even a little."}]}]}]},{"type":"thusnessPillar","content":[{"type":"paragraph","content":[{"type":"text","text":"Let the small no be seen, not solved."}]}]},{"type":"thusnessSectionMark","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Sit together"}]}]},{"type":"paragraph","content":[{"type":"text","text":"A quiet hour of guided noticing, with space for sharing. Held on Zoom."}]},{"type":"thusnessSessionGrid","content":[{"type":"thusnessSessionCard","content":[{"type":"paragraph","content":[{"type":"text","text":"~ I"}]},{"type":"paragraph","content":[{"type":"text","text":"Wednesday"}]},{"type":"paragraph","content":[{"type":"text","text":"09:00 — 10:00"}]},{"type":"paragraph","content":[{"type":"text","text":"Pacific Time"}]}]},{"type":"thusnessSessionCard","content":[{"type":"paragraph","content":[{"type":"text","text":"~ II"}]},{"type":"paragraph","content":[{"type":"text","text":"Friday"}]},{"type":"paragraph","content":[{"type":"text","text":"09:00 — 10:00"}]},{"type":"paragraph","content":[{"type":"text","text":"Pacific Time"}]}]}]},{"type":"thusnessZoomBlock","content":[{"type":"paragraph","content":[{"type":"text","text":"https://thusness.as.me/","marks":[{"type":"link","attrs":{"href":"https://thusness.as.me/"}}]}]},{"type":"paragraph","content":[{"type":"text","text":"All are welcome."}]}]}]}
$R1$::jsonb,
    updated_at = now()
where slug = 'noticing-resistance';

update public.notes
set content_json = $E1$
{"type":"doc","content":[{"type":"thusnessHero","content":[{"type":"paragraph","content":[{"type":"text","text":"What if control and effortlessness are not opposites in the way the mind assumes?"}]},{"type":"paragraph","content":[{"type":"text","text":"— a question to sit with —"}]}]},{"type":"thusnessSectionMark","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Theme · Effort and ease"}]}]},{"type":"paragraph","content":[{"type":"text","text":"There is a familiar oscillation: either I am steering hard, or I have given up and gone slack. Neither quite fits what we touched on today."}]},{"type":"thusnessPullQuote","content":[{"type":"paragraph","content":[{"type":"text","text":"What if \"doing\" can lighten without the whole scene falling apart?"}]}]},{"type":"thusnessRuleList","content":[{"type":"paragraph","content":[{"type":"text","text":"~ What we noticed"}]},{"type":"thusnessRuleListItem","content":[{"type":"paragraph","content":[{"type":"text","text":"We stayed with small moments—typing, walking, listening—where the grip shows itself first. Not to fix the grip, only to see its temperature and texture."}]}]},{"type":"thusnessRuleListItem","content":[{"type":"paragraph","content":[{"type":"text","text":"From there, the same action sometimes continues with less commentary, as though the body already knew how."}]}]}]},{"type":"thusnessRuleList","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Closing"}]},{"type":"thusnessRuleListItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Nothing to prove here. Just a record: the day leaned toward less forcing, and the world did not end."}]}]}]},{"type":"thusnessPillar","content":[{"type":"paragraph","content":[{"type":"text","text":"Less forcing; nothing lost."}]}]},{"type":"thusnessSectionMark","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Sit together"}]}]},{"type":"paragraph","content":[{"type":"text","text":"Weekly sessions hold space for this kind of inquiry. Held on Zoom."}]},{"type":"thusnessSessionGrid","content":[{"type":"thusnessSessionCard","content":[{"type":"paragraph","content":[{"type":"text","text":"~ I"}]},{"type":"paragraph","content":[{"type":"text","text":"Wednesday"}]},{"type":"paragraph","content":[{"type":"text","text":"09:00 — 10:00"}]},{"type":"paragraph","content":[{"type":"text","text":"Pacific Time"}]}]},{"type":"thusnessSessionCard","content":[{"type":"paragraph","content":[{"type":"text","text":"~ II"}]},{"type":"paragraph","content":[{"type":"text","text":"Friday"}]},{"type":"paragraph","content":[{"type":"text","text":"09:00 — 10:00"}]},{"type":"paragraph","content":[{"type":"text","text":"Pacific Time"}]}]}]},{"type":"thusnessZoomBlock","content":[{"type":"paragraph","content":[{"type":"text","text":"https://thusness.as.me/","marks":[{"type":"link","attrs":{"href":"https://thusness.as.me/"}}]}]},{"type":"paragraph","content":[{"type":"text","text":"All are welcome."}]}]}]}
$E1$::jsonb,
    updated_at = now()
where slug = 'effortlessness-and-control';

update public.notes
set content_json = $A1$
{"type":"doc","content":[{"type":"thusnessHero","content":[{"type":"paragraph","content":[{"type":"text","text":"What changes when experience is allowed to arrive before the story about it?"}]},{"type":"paragraph","content":[{"type":"text","text":"— a question to sit with —"}]}]},{"type":"thusnessSectionMark","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Theme · As it is"}]}]},{"type":"paragraph","content":[{"type":"text","text":"We began where we always begin, which is here: sound in the room, weight in the chair, the hum of thinking doing what thinking does."}]},{"type":"thusnessPullQuote","content":[{"type":"paragraph","content":[{"type":"text","text":"\"As it is\" is easy to repeat and hard to mean. Today it meant pausing the habit of gently bullying experience into a better shape before looking."}]}]},{"type":"thusnessRuleList","content":[{"type":"paragraph","content":[{"type":"text","text":"~ What showed up"}]},{"type":"thusnessRuleListItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Not dramatic. Colors a little clearer. Silence with more room in it. A sense that the narrative could arrive a half-step later and nothing would be lost."}]}]}]},{"type":"thusnessRuleList","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Honest summary"}]},{"type":"thusnessRuleListItem","content":[{"type":"paragraph","content":[{"type":"text","text":"If someone reads this later and wonders what happened in the session, the honest answer is: not much, in the best sense. A few minutes of not lying to oneself about what was already present."}]}]}]},{"type":"thusnessPillar","content":[{"type":"paragraph","content":[{"type":"text","text":"Here first. Story second."}]}]},{"type":"thusnessSectionMark","content":[{"type":"paragraph","content":[{"type":"text","text":"~ Sit together"}]}]},{"type":"paragraph","content":[{"type":"text","text":"A quiet hour of guided noticing, with space for sharing. Held on Zoom."}]},{"type":"thusnessSessionGrid","content":[{"type":"thusnessSessionCard","content":[{"type":"paragraph","content":[{"type":"text","text":"~ I"}]},{"type":"paragraph","content":[{"type":"text","text":"Wednesday"}]},{"type":"paragraph","content":[{"type":"text","text":"09:00 — 10:00"}]},{"type":"paragraph","content":[{"type":"text","text":"Pacific Time"}]}]},{"type":"thusnessSessionCard","content":[{"type":"paragraph","content":[{"type":"text","text":"~ II"}]},{"type":"paragraph","content":[{"type":"text","text":"Friday"}]},{"type":"paragraph","content":[{"type":"text","text":"09:00 — 10:00"}]},{"type":"paragraph","content":[{"type":"text","text":"Pacific Time"}]}]}]},{"type":"thusnessZoomBlock","content":[{"type":"paragraph","content":[{"type":"text","text":"https://thusness.as.me/","marks":[{"type":"link","attrs":{"href":"https://thusness.as.me/"}}]}]},{"type":"paragraph","content":[{"type":"text","text":"All are welcome."}]}]}]}
$A1$::jsonb,
    updated_at = now()
where slug = 'as-it-is';
